--
-- Table structure for table `financial_statements`
--

DROP TABLE IF EXISTS `financial_statements`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `financial_statements` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `user_id` int unsigned NOT NULL,
  `admin_id` int unsigned DEFAULT NULL,
  `contract_id` int unsigned DEFAULT NULL COMMENT 'Null if standard account deposit/withdrawal',
  `operation_type` enum('deposit','withdrawal','margin_lock','limit_release','partial_amortization','full_settlement','late_fee') NOT NULL,
  `nature` enum('C','D') NOT NULL COMMENT 'C = Credit (In), D = Debit (Out)',
  `amount` decimal(15,2) NOT NULL,
  `description` varchar(255) NOT NULL,
  `attachment` varchar(255) DEFAULT NULL,
  `payment_method` varchar(50) DEFAULT NULL,
  `notes` text,
  `transaction_date` datetime NOT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `fee_percent` decimal(18,4) DEFAULT NULL,
  `comercial_brl` decimal(18,2) DEFAULT NULL,
  `fee_brl` decimal(18,2) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_statement_user` (`user_id`),
  KEY `fk_statement_contract` (`contract_id`),
  KEY `fk_statement_admin` (`admin_id`),
  CONSTRAINT `fk_statement_admin` FOREIGN KEY (`admin_id`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `fk_statement_contract` FOREIGN KEY (`contract_id`) REFERENCES `contracts` (`id`) ON DELETE RESTRICT,
  CONSTRAINT `fk_statement_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE RESTRICT
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

