DROP TABLE IF EXISTS `users`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `users` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `name` varchar(100) COLLATE utf8mb4_general_ci NOT NULL,
  `company_name` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `phone` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `cnpj` varchar(20) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `login` varchar(150) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `password` varchar(255) COLLATE utf8mb4_general_ci NOT NULL,
  `role` enum('admin','operator','user') COLLATE utf8mb4_general_ci DEFAULT 'user',
  `fee_percent` decimal(10,2) DEFAULT '10.00',
  `credit_limit` decimal(10,2) DEFAULT '0.00',
  `default_contract_type` enum('d+1','d+2') COLLATE utf8mb4_general_ci DEFAULT 'd+1',
  `daily_interest_rate` decimal(5,2) DEFAULT '0.00',
  `allowed_delivery_types` enum('D+0','D+1','D+2','all') COLLATE utf8mb4_general_ci DEFAULT 'all',
  `language` varchar(10) COLLATE utf8mb4_general_ci DEFAULT 'pt-BR',
  `usdt_wallet` varchar(255) COLLATE utf8mb4_general_ci DEFAULT NULL,
  `created_at` datetime DEFAULT NULL,
  `updated_at` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `email` (`login`),
  UNIQUE KEY `login` (`login`)
) ENGINE=InnoDB AUTO_INCREMENT=8 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

